fn solve(n: i64) -> i64 = {
    if n < 0 { return n };
    let mut depth = 0;
    while n >= 10 {
        n = n / 10;
        depth = depth + 1
    };
    depth
};

fn main() -> i64 = {
    let t = read_int();
    let i = 0;
    while i < t {
        let n = read_int();
        let _p = println(solve(n));
        i = i + 1
    };
    0
};

